INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES ("", 0, "", 72, "", 21, "", 72028, "vo_asb", 0, "vo_asb_0725");
