INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, 10, 0, 82, 1, 11, 0, 82029, 1, 1, "柔和で、寛容で、お話のわかる……\n彼女こそ、真の保育士さんで\nいらっしゃいますね。");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES ("", 0, "", 82, "", 91, "", 82030, 0, 0, "");
