INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, 10, 0, 142, 1, 11, 0, 142020, 1, 1, "まだ卵焼きすらも\n焦がしてしまう分際で、\nつい、出過ぎたことを\n夢想してしまいました。");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES ("", 0, "", 142, "", 91, "", 142021, 0, 0, "");
